import { Link } from 'react-router-dom';
import { useState, useEffect, useRef } from 'react';

const categories = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact'];

const PROJECTS = [
  {
    name: 'NeuroSync Headband',
    category: 'Health',
    desc: 'EEG-powered focus optimizer for remote workers',
    scores: { Feasibility: 91, 'Market Fit': 87, Innovation: 95, 'Team Strength': 82 },
    verdict: 'APPROVED',
    tag: '🧠 Health Tech',
  },
  {
    name: 'SolarPack Backpack',
    category: 'Technology',
    desc: 'Flexible solar panels integrated into everyday carry',
    scores: { Feasibility: 88, 'Market Fit': 93, Innovation: 79, 'Team Strength': 90 },
    verdict: 'APPROVED',
    tag: '⚡ CleanTech',
  },
  {
    name: 'EduBot Classrooms',
    category: 'Education',
    desc: 'AI tutor that adapts to each student\'s learning pace',
    scores: { Feasibility: 84, 'Market Fit': 96, Innovation: 88, 'Team Strength': 77 },
    verdict: 'APPROVED',
    tag: '📚 EdTech',
  },
];

function useAnimatedScore(target, running) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!running) { setVal(0); return; }
    let start = null;
    const duration = 900 + Math.random() * 400;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      setVal(Math.round(p * target));
      if (p < 1) requestAnimationFrame(step);
    };
    const id = requestAnimationFrame(step);
    return () => cancelAnimationFrame(id);
  }, [target, running]);
  return val;
}

function ScoreBar({ label, target, running, delay }) {
  const [active, setActive] = useState(false);
  useEffect(() => {
    if (!running) { setActive(false); return; }
    const t = setTimeout(() => setActive(true), delay);
    return () => clearTimeout(t);
  }, [running, delay]);
  const val = useAnimatedScore(target, active);
  const color = target >= 90 ? '#00d4aa' : target >= 80 ? '#f59e0b' : '#6366f1';
  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
        <span style={{ color: '#9ca3af', fontSize: 12, letterSpacing: '0.05em' }}>{label}</span>
        <span style={{ color, fontWeight: 700, fontSize: 13, fontFamily: 'Syne, sans-serif' }}>{val}<span style={{ color: '#4b5563', fontWeight: 400 }}>/100</span></span>
      </div>
      <div style={{ background: '#1f2937', borderRadius: 99, height: 6, overflow: 'hidden' }}>
        <div style={{
          height: '100%', borderRadius: 99, background: color,
          width: active ? `${val}%` : '0%',
          transition: 'width 0.05s linear',
          boxShadow: `0 0 8px ${color}88`
        }} />
      </div>
    </div>
  );
}

function AIEvaluatorWidget() {
  const [idx, setIdx] = useState(0);
  const [phase, setPhase] = useState('idle'); // idle | scanning | scored
  const [dots, setDots] = useState('');
  const proj = PROJECTS[idx];

  useEffect(() => {
    setPhase('idle');
    const t1 = setTimeout(() => setPhase('scanning'), 300);
    return () => clearTimeout(t1);
  }, [idx]);

  useEffect(() => {
    if (phase === 'scanning') {
      const t = setTimeout(() => setPhase('scored'), 2200);
      return () => clearTimeout(t);
    }
  }, [phase]);

  useEffect(() => {
    if (phase !== 'scanning') return;
    const iv = setInterval(() => setDots(d => d.length >= 3 ? '' : d + '.'), 420);
    return () => clearInterval(iv);
  }, [phase]);

  const overallScore = Math.round(Object.values(proj.scores).reduce((a, b) => a + b, 0) / 4);

  return (
    <div style={{ borderTop: '1px solid #1f2937', borderBottom: '1px solid #1f2937' }} className="py-16">
      <div className="max-w-4xl mx-auto px-6">
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <span style={{ background: 'rgba(0,212,170,0.1)', border: '1px solid rgba(0,212,170,0.25)', color: '#00d4aa', fontSize: 11, letterSpacing: '0.15em', padding: '4px 14px', borderRadius: 99, textTransform: 'uppercase', fontWeight: 600 }}>
            ✦ Live AI Evaluation Preview
          </span>
          <h2 style={{ fontFamily: 'Syne, sans-serif', fontSize: 28, fontWeight: 800, marginTop: 14, marginBottom: 6, color: '#f9fafb' }}>
            Watch Gemini Score a Project
          </h2>
          <p style={{ color: '#6b7280', fontSize: 14 }}>Real AI insights before a single backer clicks "Fund"</p>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, alignItems: 'stretch' }}>
          {/* Left: Project card + selector */}
          <div style={{ background: '#0f1623', border: '1px solid #1f2937', borderRadius: 20, padding: 28, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
            <div>
              <div style={{ display: 'flex', gap: 8, marginBottom: 20, flexWrap: 'wrap' }}>
                {PROJECTS.map((p, i) => (
                  <button key={p.name} onClick={() => setIdx(i)}
                    style={{
                      padding: '6px 14px', borderRadius: 99, fontSize: 12, fontWeight: 600, cursor: 'pointer', transition: 'all 0.2s',
                      background: i === idx ? 'rgba(0,212,170,0.15)' : 'transparent',
                      border: i === idx ? '1px solid rgba(0,212,170,0.5)' : '1px solid #1f2937',
                      color: i === idx ? '#00d4aa' : '#6b7280',
                    }}>
                    Project {i + 1}
                  </button>
                ))}
              </div>
              <div style={{ fontSize: 11, color: '#00d4aa', letterSpacing: '0.1em', marginBottom: 8, fontWeight: 600 }}>{proj.tag}</div>
              <h3 style={{ fontFamily: 'Syne, sans-serif', fontSize: 22, fontWeight: 800, color: '#f9fafb', marginBottom: 8, lineHeight: 1.2 }}>{proj.name}</h3>
              <p style={{ color: '#6b7280', fontSize: 13, lineHeight: 1.6 }}>{proj.desc}</p>
            </div>
            <div style={{ marginTop: 24, padding: '14px 18px', background: '#111827', borderRadius: 12, border: '1px solid #1f2937' }}>
              <div style={{ fontSize: 11, color: '#4b5563', letterSpacing: '0.1em', marginBottom: 4 }}>CATEGORY</div>
              <div style={{ color: '#d1d5db', fontSize: 14, fontWeight: 600 }}>{proj.category}</div>
            </div>
          </div>

          {/* Right: AI scoring panel */}
          <div style={{ background: '#0f1623', border: '1px solid #1f2937', borderRadius: 20, padding: 28, position: 'relative', overflow: 'hidden' }}>
            {/* Subtle grid bg */}
            <div style={{
              position: 'absolute', inset: 0, opacity: 0.03,
              backgroundImage: 'linear-gradient(#00d4aa 1px, transparent 1px), linear-gradient(90deg, #00d4aa 1px, transparent 1px)',
              backgroundSize: '24px 24px'
            }} />
            <div style={{ position: 'relative' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 22 }}>
                <div style={{ width: 8, height: 8, borderRadius: '50%', background: phase === 'scanning' ? '#f59e0b' : phase === 'scored' ? '#00d4aa' : '#374151', boxShadow: phase === 'scanning' ? '0 0 8px #f59e0b' : phase === 'scored' ? '0 0 8px #00d4aa' : 'none', transition: 'all 0.3s' }} />
                <span style={{ fontSize: 11, color: '#6b7280', letterSpacing: '0.12em', textTransform: 'uppercase', fontWeight: 600 }}>
                  {phase === 'idle' ? 'Gemini AI' : phase === 'scanning' ? `Analyzing${dots}` : 'Evaluation Complete'}
                </span>
              </div>

              {Object.entries(proj.scores).map(([label, target], i) => (
                <ScoreBar key={label + idx} label={label} target={target} running={phase === 'scored'} delay={i * 160} />
              ))}

              <div style={{ marginTop: 22, padding: '16px 20px', borderRadius: 14, background: phase === 'scored' ? 'rgba(0,212,170,0.08)' : '#111827', border: `1px solid ${phase === 'scored' ? 'rgba(0,212,170,0.3)' : '#1f2937'}`, transition: 'all 0.5s', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <div>
                  <div style={{ fontSize: 11, color: '#4b5563', letterSpacing: '0.1em', marginBottom: 2 }}>OVERALL SCORE</div>
                  <div style={{ fontFamily: 'Syne, sans-serif', fontSize: 32, fontWeight: 900, color: phase === 'scored' ? '#00d4aa' : '#1f2937', transition: 'color 0.5s', lineHeight: 1 }}>
                    {phase === 'scored' ? overallScore : '--'}
                  </div>
                </div>
                <div style={{
                  padding: '8px 18px', borderRadius: 99, fontWeight: 800, fontSize: 13, letterSpacing: '0.1em',
                  background: phase === 'scored' ? 'rgba(0,212,170,0.15)' : 'transparent',
                  color: phase === 'scored' ? '#00d4aa' : '#1f2937',
                  border: `1px solid ${phase === 'scored' ? 'rgba(0,212,170,0.4)' : '#1f2937'}`,
                  transition: 'all 0.5s'
                }}>
                  {phase === 'scored' ? '✓ ' + proj.verdict : '···'}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function Landing() {
  return (
    <div style={{ background: '#0a0d1a' }} className="min-h-screen">
      {/* Hero */}
      <section className="relative px-6 pt-28 pb-32 text-center overflow-hidden">
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.15,
          background: 'radial-gradient(ellipse 80% 60% at 50% -20%, #00d4aa, transparent)'
        }} />
        <div className="relative max-w-4xl mx-auto">
          <div style={{ background: 'rgba(0,212,170,0.1)', border: '1px solid rgba(0,212,170,0.3)', color: '#00d4aa' }}
               className="inline-block px-4 py-1.5 rounded-full text-sm font-medium mb-6">
            ✦ AI-Powered Crowdfunding Platform
          </div>
          <h1 style={{ fontFamily: 'Syne, sans-serif' }}
              className="text-6xl font-black mb-6 leading-none tracking-tight">
            Fund the Future.<br />
            <span style={{ color: '#00d4aa' }}>Backed by AI.</span>
          </h1>
          <p className="text-gray-400 text-xl mb-10 max-w-2xl mx-auto leading-relaxed">
            BackerSphere X uses Google Gemini to evaluate every project for feasibility and success potential.
            Smarter funding decisions. Better outcomes.
          </p>
          <div className="flex gap-4 justify-center flex-wrap">
            <Link to="/register"
              style={{ background: '#00d4aa', color: '#0a0d1a' }}
              className="px-8 py-3.5 rounded-xl font-bold text-lg hover:opacity-90 transition-all shadow-lg">
              Start a Project →
            </Link>
            <Link to="/projects"
              style={{ border: '1px solid #374151', color: '#d1d5db' }}
              className="px-8 py-3.5 rounded-xl font-semibold text-lg hover:border-gray-500 transition-all">
              Browse Projects
            </Link>
          </div>
        </div>
      </section>

      {/* ✦ NEW: Live AI Evaluator Widget */}
      <AIEvaluatorWidget />

      {/* How It Works */}
      <section className="py-20 px-6 max-w-5xl mx-auto">
        <h2 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold text-center mb-14">
          How BackerSphere X Works
        </h2>
        <div className="grid grid-cols-3 gap-6">
          {[
            { step: '01', title: 'Submit Your Project', desc: 'Innovators submit their idea with goals, timeline, and team details.' },
            { step: '02', title: 'AI Evaluation', desc: 'Gemini AI scores feasibility and success probability instantly.' },
            { step: '03', title: 'Admin Review', desc: 'Admin uses AI insights to approve or reject — then backers fund it.' },
          ].map(s => (
            <div key={s.step} style={{ background: '#111827', border: '1px solid #1f2937' }}
                 className="p-6 rounded-2xl">
              <div style={{ color: '#00d4aa', fontFamily: 'Syne, sans-serif' }} className="text-4xl font-black mb-3 opacity-40">{s.step}</div>
              <h3 className="font-bold text-lg mb-2">{s.title}</h3>
              <p className="text-gray-400 text-sm leading-relaxed">{s.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Categories */}
      <section className="py-12 px-6 max-w-4xl mx-auto text-center">
        <p className="text-gray-500 text-sm uppercase tracking-widest mb-6">Project Categories</p>
        <div className="flex flex-wrap gap-3 justify-center">
          {categories.map(cat => (
            <Link key={cat} to={`/projects?category=${cat}`}
              style={{ background: '#111827', border: '1px solid #1f2937', color: '#9ca3af' }}
              className="px-5 py-2 rounded-full text-sm hover:border-teal-500 hover:text-white transition-all">
              {cat}
            </Link>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="py-20 px-6 text-center">
        <div style={{ background: 'linear-gradient(135deg, rgba(0,212,170,0.1), rgba(245,158,11,0.05))', border: '1px solid rgba(0,212,170,0.2)' }}
             className="max-w-2xl mx-auto p-12 rounded-3xl">
          <h2 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold mb-4">Ready to back great ideas?</h2>
          <p className="text-gray-400 mb-8">Join thousands of backers supporting AI-vetted innovations.</p>
          <Link to="/register"
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="px-10 py-3.5 rounded-xl font-bold text-lg inline-block hover:opacity-90 transition-all">
            Join as a Backer
          </Link>
        </div>
      </section>

      <footer style={{ borderTop: '1px solid #1f2937' }} className="py-8 text-center text-gray-600 text-sm">
        © 2024 BackerSphere X · Powered by Google Gemini AI
      </footer>
    </div>
  );
}
